INSERT INTO products (name, slug, description, specifications, price, discount_price, stock_quantity, category, brand, featured, best_seller, new_arrival, images) VALUES
('Royal Mariner Chronograph', 'royal-mariner-chronograph', 'A masterpiece of precision engineering, the Royal Mariner Chronograph features a Swiss automatic movement housed in a 316L stainless steel case. The sapphire crystal face reveals intricate mechanical artistry, while the genuine leather strap ensures all-day comfort. Water-resistant to 200 meters.', '{"Movement": "Swiss Automatic", "Case Material": "316L Stainless Steel", "Crystal": "Sapphire", "Water Resistance": "200m", "Strap": "Genuine Leather", "Diameter": "42mm", "Thickness": "12mm", "Power Reserve": "48 hours"}', 2850000, 2500000, 15, 'Chronograph', 'Royal Mariner', true, true, false, ARRAY['https://images.unsplash.com/photo-1524592094714-0f0654e20314?w=800', 'https://images.unsplash.com/photo-1522312346375-d1a52e2b99b3?w=800']),
INSERT INTO banners (title, subtitle, image, link, active, "order") VALUES
('Timeless Elegance on Every Wrist', 'Discover our curated collection of luxury timepieces crafted for those who appreciate the finer things in life.', 'https://images.unsplash.com/photo-1523170335258-f5ed11844a49?w=1600', '/shop', true, 1),
('New Arrivals: The Summit Collection', 'Explore our latest additions featuring titanium cases and advanced sensor technology.', 'https://images.unsplash.com/photo-1524592094714-0f0654e20314?w=1600', '/shop?filter=new', true, 2),
('Heritage Classic: A Legacy of Craftsmanship', 'Experience the art of traditional watchmaking with our Heritage collection.', 'https://images.unsplash.com/photo-1547996663-b0f255ffb89d?w=1600', '/shop?filter=heritage', true, 3);
INSERT INTO testimonials (name, location, comment, rating) VALUES
('James Ochieng', 'Kampala, Uganda', 'The Royal Mariner Chronograph exceeded all my expectations. The craftsmanship is impeccable and the customer service was outstanding. I have received countless compliments on this timepiece.', 5),
('Amina Hassan', 'Nairobi, Kenya', 'I purchased the Elegance Rose Gold as a gift for my mother and she absolutely loves it. The packaging was luxurious and the watch itself is stunning. Aura & Anchor truly understands luxury.', 5),
('David Mwangi', 'Kigali, Rwanda', 'Fast shipping across East Africa and the watch arrived in perfect condition. The Ocean Master Diver Pro is built like a tank. I have been wearing it daily for 6 months without any issues.', 5),
('Sarah Nambafu', 'Dar es Salaam, Tanzania', 'The attention to detail is remarkable. From the website experience to unboxing, everything felt premium. The Heritage Classic Gold is now my go-to dress watch for every formal event.', 4),
('Peter Okello', 'Juba, South Sudan', 'As a collector, I appreciate authenticity and quality. Aura & Anchor delivers both. Their collection is carefully curated and their team is knowledgeable about every piece they sell.', 5);
INSERT INTO faqs (question, answer, "order") VALUES
('How do I know your watches are authentic?', 'Every watch in our collection comes with a certificate of authenticity and manufacturer warranty. We source directly from authorized distributors and renowned watchmakers. Your purchase is 100% guaranteed authentic.', 1),
('What payment methods do you accept?', 'We accept MTN Mobile Money, Airtel Money, cash on delivery, and bank transfers. All payments are processed securely through our encrypted payment gateway.', 2),
('How long does delivery take?', 'Delivery within Uganda takes 1-2 business days. To Kenya, Tanzania, Rwanda, and other East African countries, delivery takes 3-5 business days. All shipments are fully insured.', 3),
('Do you offer warranty on your watches?', 'Yes, all watches come with a minimum 2-year manufacturer warranty. We also provide our own 30-day satisfaction guarantee. If you are not completely satisfied, you can return the watch for a full refund.', 4),
('Can I track my order?', 'Absolutely. Once your order is shipped, you will receive a tracking number via SMS and email. You can also track your order on our website using your order number.', 5),
('Do you offer watch servicing?', 'Yes, we have partnerships with certified watchmakers across East Africa. Contact us for servicing, battery replacement, or strap changes.', 6);
